import { Chain, Link, State } from 'codeuchain';

const pipeline = new Chain()
  .addLink(new Link('validate', ctx => {
    if (!ctx.get('email').includes('@'))
      throw new Error('Invalid email');
    return ctx;
  }))
  .addLink(new Link('save', ctx => {
    ctx.set('user_id', 42);
    return ctx;
  }));

const result = pipeline.execute(
  new State({ email: 'user@example.com' })
);
console.log('User ID:', result.get('user_id'));
